  1→import { getSheetDisplayLabel } from '@/domain/sheetModels';
  2→import {
  3→  DRAWING_GRAPHICS,
  4→  SHEET_COLORS,
  5→  SHEET_TOKENS,
  6→  resolveSheetMetadata,
  7→  resolveViewportReferenceNote,
  8→  resolveViewportScaleLabel,
  9→  snapRectToGrid,
 10→} from './standards';
 11→import { getPaperPreset } from './paper';
 12→import { getViewportSourceLabel, resolveSheetViewportSource } from './sources';
 13→
 14→function clamp(value, min, max) {
 15→  return Math.max(min, Math.min(max, value));
 16→}
 17→
 18→function resolveViewportScale(viewport) {
 19→  return Math.max(1, Number(viewport?.scale) || 100);
 20→}
 21→
 22→function getCaptionClearance(viewport) {
 23→  if (viewport?.captionPosition === 'above' || viewport?.captionPosition === 'below') {
 24→    return SHEET_TOKENS.viewportCaptionGap + SHEET_TOKENS.viewportCaptionHeight;
 25→  }
 26→  return 0;
 27→}
 28→
 29→function buildSheetZones(paper) {
 30→  const border = {
 31→    x: SHEET_TOKENS.margin,
 32→    y: SHEET_TOKENS.margin,
 33→    width: paper.width - SHEET_TOKENS.margin * 2,
 34→    height: paper.height - SHEET_TOKENS.margin * 2,
 35→  };
 36→
 37→  const liveArea = {
 38→    x: border.x + SHEET_TOKENS.innerInset,
 39→    y: border.y + SHEET_TOKENS.innerInset,
 40→    width: border.width - SHEET_TOKENS.innerInset * 2,
 41→    height: border.height - SHEET_TOKENS.innerInset * 2,
 42→  };
 43→
 44→  const footer = {
 45→    x: liveArea.x,
 46→    y: liveArea.y + liveArea.height - SHEET_TOKENS.footerHeight,
 47→    width: liveArea.width,
 48→    height: SHEET_TOKENS.footerHeight,
 49→  };
 50→
 51→  const contentArea = {
 52→    x: liveArea.x,
 53→    y: liveArea.y,
 54→    width: liveArea.width,
 55→    height: footer.y - liveArea.y - SHEET_TOKENS.contentGap,
 56→  };
 57→
 58→  const titleBlock = {
 59→    x: footer.x + footer.width - Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 60→    y: footer.y,
 61→    width: Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 62→    height: footer.height,
 63→  };
 64→
 65→  return {
 66→    border,
 67→    liveArea,
 68→    footer,
 69→    contentArea,
 70→    titleBlock,
 71→  };
 72→}
 73→
 74→function resolveViewportTitle(viewport, source) {
 75→  return viewport.title?.trim() || source.title || getViewportSourceLabel(viewport.sourceView);
 76→}
 77→
 78→function formatCaptionSecondary(viewport, source, sheet) {
 79→  const scaleLabel = resolveViewportScaleLabel(viewport, source, sheet);
 80→  const reference = resolveViewportReferenceNote(viewport, source);
 81→  return `${reference}  |  SCALE ${scaleLabel}`;
 82→}
 83→
 84→function buildContentTransform(viewport, source, contentRect) {
 85→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 86→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 87→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 88→  const scale = source.kind === '3d_preview'
 89→    ? Math.min(contentRect.width / sourceWidth, contentRect.height / sourceHeight)
 90→    : (1 / resolveViewportScale(viewport));
 91→
 92→  const drawnWidth = sourceWidth * scale;
 93→  const drawnHeight = sourceHeight * scale;
 94→  const translateX = (contentRect.width - drawnWidth) / 2 - bounds.minX * scale;
 95→  const translateY = (contentRect.height - drawnHeight) / 2 - bounds.minY * scale;
 96→
 97→  return {
 98→    scale,
 99→    translateX,
100→    translateY,
101→  };
102→}
103→
104→function buildViewportScene(viewport, source, sheet, rect) {
105→  const frameRect = snapRectToGrid(rect);
106→  const contentRect = {
107→    x: frameRect.x + SHEET_TOKENS.viewportPadding,
108→    y: frameRect.y + SHEET_TOKENS.viewportPadding,
109→    width: Math.max(10, frameRect.width - SHEET_TOKENS.viewportPadding * 2),
110→    height: Math.max(10, frameRect.height - SHEET_TOKENS.viewportPadding * 2),
111→  };
112→
113→  const captionGap = SHEET_TOKENS.viewportCaptionGap;
114→  const captionHeight = SHEET_TOKENS.viewportCaptionHeight;
115→  const captionY = viewport.captionPosition === 'above'
116→    ? frameRect.y - captionGap
117→    : frameRect.y + frameRect.height + captionGap + captionHeight;
118→
119→  const caption = {
120→    position: viewport.captionPosition || 'below',
121→    x: frameRect.x,
122→    y: captionY,
123→    width: frameRect.width,
124→    primaryText: resolveViewportTitle(viewport, source),
125→    secondaryText: formatCaptionSecondary(viewport, source, sheet),
126→  };
127→
128→  return {
129→    ...viewport,
130→    x: frameRect.x,
131→    y: frameRect.y,
132→    width: frameRect.width,
133→    height: frameRect.height,
134→    title: caption.primaryText,
135→    source,
136→    frameRect,
137→    clipRect: contentRect,
138→    contentRect,
139→    caption,
140→    contentTransform: buildContentTransform(viewport, source, contentRect),
141→    autoLayoutApplied: !viewport.lockAutoLayout,
142→  };
143→}
144→
145→function buildTitleBlock(project, sheet, titleBlockRect, index, viewports) {
146→  const meta = resolveSheetMetadata(project, sheet, index, viewports);
147→  const revisionWidth = Math.max(44, titleBlockRect.width * 0.28);
148→  const infoX = titleBlockRect.x + titleBlockRect.width - revisionWidth;
149→  const mainWidth = titleBlockRect.width - revisionWidth;
150→  const bandHeight = titleBlockRect.height * 0.3;
151→  const titleHeight = titleBlockRect.height * 0.36;
152→  const metaRowHeight = (titleBlockRect.height - bandHeight - titleHeight) / 2;
153→  const metaLabelWidth = 15;
154→  const visibleRevisions = [...(sheet?.revisions || [])].slice(-4).reverse();
155→
156→  return {
157→    frame: titleBlockRect,
158→    projectBand: {
159→      x: titleBlockRect.x,
160→      y: titleBlockRect.y,
161→      width: mainWidth,
162→      height: bandHeight,
163→      title: meta.projectTitle,
164→      address: meta.projectAddress,
165→    },
166→    drawingCell: {
167→      x: titleBlockRect.x,
168→      y: titleBlockRect.y + bandHeight,
169→      width: mainWidth * 0.68,
170→      height: titleHeight,
171→      label: 'DRAWING TITLE',
172→      value: meta.drawingTitle,
173→    },
174→    numberCell: {
175→      x: titleBlockRect.x + mainWidth * 0.68,
176→      y: titleBlockRect.y + bandHeight,
177→      width: mainWidth * 0.32,
178→      height: titleHeight,
179→      label: 'SHEET NO.',
180→      value: meta.sheetNumber,
181→    },
182→    metaRows: [
183→      {
184→        x: titleBlockRect.x,
185→        y: titleBlockRect.y + bandHeight + titleHeight,
186→        width: mainWidth / 2,
187→        height: metaRowHeight,
188→        labelWidth: metaLabelWidth,
189→        label: 'DATE',
190→        value: meta.issueDate,
191→      },
192→      {
193→        x: titleBlockRect.x + mainWidth / 2,
194→        y: titleBlockRect.y + bandHeight + titleHeight,
195→        width: mainWidth / 2,
196→        height: metaRowHeight,
197→        labelWidth: metaLabelWidth,
198→        label: 'SCALE',
199→        value: meta.scaleLabel,
200→      },
201→      {
202→        x: titleBlockRect.x,
203→        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
204→        width: mainWidth / 2,
205→        height: metaRowHeight,
206→        labelWidth: metaLabelWidth,
207→        label: 'DRAWN BY',
208→        value: meta.drawnBy || 'TBD',
209→      },
210→      {
211→        x: titleBlockRect.x + mainWidth / 2,
212→        y: titleBlockRect.y + bandHeight + titleHeight + metaRowHeight,
213→        width: mainWidth / 2,
214→        height: metaRowHeight,
215→        labelWidth: metaLabelWidth,
216→        label: 'CHECKED',
217→        value: meta.checkedBy || 'TBD',
218→      },
219→    ],
220→    revisions: {
221→      x: infoX,
222→      y: titleBlockRect.y,
223→      width: revisionWidth,
224→      height: titleBlockRect.height,
225→      headerHeight: 8,
226→      rows: visibleRevisions,
227→    },
228→  };
229→}
230→
231→function rectFromArea(area) {
232→  return {
233→    x: area.x,
234→    y: area.y,
235→    width: area.width,
236→    height: area.height,
237→  };
238→}
239→
240→function partitionByRole(entries) {
241→  const primary = [];
242→  const secondary = [];
243→  const supplemental = [];
244→
245→  entries.forEach((entry, index) => {
246→    const role = entry.viewport.role
247→      || (entry.source.kind === '3d_preview' ? 'supplemental' : (index === 0 ? 'primary' : 'secondary'));
248→
249→    if (role === 'supplemental' || entry.source.kind === '3d_preview') {
250→      supplemental.push(entry);
251→    } else if (role === 'primary') {
252→      primary.push(entry);
253→    } else {
254→      secondary.push(entry);
255→    }
256→  });
257→
258→  return { primary, secondary, supplemental };
259→}
260→
261→function stackAreas(area, count) {
262→  if (count <= 0) return [];
263→  if (count === 1) return [rectFromArea(area)];
264→  if (count >= 4) {
265→    const columns = 2;
266→    const rows = Math.ceil(count / columns);
267→    const cellWidth = (area.width - SHEET_TOKENS.viewportGutter) / columns;
268→    const cellHeight = (area.height - SHEET_TOKENS.viewportGutter * (rows - 1)) / rows;
269→    return Array.from({ length: count }, (_, index) => {
270→      const column = index % columns;
271→      const row = Math.floor(index / columns);
272→      return {
273→        x: area.x + column * (cellWidth + SHEET_TOKENS.viewportGutter),
274→        y: area.y + row * (cellHeight + SHEET_TOKENS.viewportGutter),
275→        width: cellWidth,
276→        height: cellHeight,
277→      };
278→    });
279→  }
280→
281→  const height = (area.height - SHEET_TOKENS.viewportGutter * (count - 1)) / count;
282→  return Array.from({ length: count }, (_, index) => ({
283→    x: area.x,
284→    y: area.y + index * (height + SHEET_TOKENS.viewportGutter),
285→    width: area.width,
286→    height,
287→  }));
288→}
289→
290→function layoutAutoViewports(entries, area) {
291→  if (!entries.length) return new Map();
292→
293→  const result = new Map();
294→  const roles = partitionByRole(entries);
295→  const primaryEntry = roles.primary[0] || roles.secondary[0] || roles.supplemental[0];
296→  const secondaryEntries = [
297→    ...roles.primary.slice(primaryEntry && roles.primary[0] === primaryEntry ? 1 : 0),
298→    ...roles.secondary.filter((entry) => entry !== primaryEntry),
299→    ...roles.supplemental.filter((entry) => entry !== primaryEntry),
300→  ];
301→
302→  if (!primaryEntry) return result;
303→
304→  const onlySupplemental = primaryEntry.source.kind === '3d_preview'
305→    && secondaryEntries.every((entry) => entry.source.kind === '3d_preview');
306→
307→  if (!secondaryEntries.length) {
308→    result.set(primaryEntry.viewport.id, rectFromArea(area));
309→    return result;
310→  }
311→
312→  if (onlySupplemental) {
313→    const areas = stackAreas(area, 1 + secondaryEntries.length);
314→    [primaryEntry, ...secondaryEntries].forEach((entry, index) => {
315→      result.set(entry.viewport.id, areas[index]);
316→    });
317→    return result;
318→  }
319→
320→  const primaryWidthRatio = secondaryEntries.length >= 3 ? 0.58 : 0.64;
321→  const primaryArea = {
322→    x: area.x,
323→    y: area.y,
324→    width: area.width * primaryWidthRatio - SHEET_TOKENS.viewportGutter / 2,
325→    height: area.height,
326→  };
327→  const sideArea = {
328→    x: primaryArea.x + primaryArea.width + SHEET_TOKENS.viewportGutter,
329→    y: area.y,
330→    width: area.width - primaryArea.width - SHEET_TOKENS.viewportGutter,
331→    height: area.height,
332→  };
333→
334→  result.set(primaryEntry.viewport.id, rectFromArea(primaryArea));
335→  stackAreas(sideArea, secondaryEntries.length).forEach((rect, index) => {
336→    result.set(secondaryEntries[index].viewport.id, rect);
337→  });
338→
339→  return result;
340→}
341→
342→export function buildSheetScene(project, sheet) {
343→  if (!sheet) return null;
344→
345→  const paper = getPaperPreset(sheet.paperSize);
346→  const zones = buildSheetZones(paper);
347→  const sourceEntries = (sheet.viewports || []).map((viewport) => ({
348→    viewport,
349→    source: resolveSheetViewportSource(project, viewport),
350→  }));
351→  const allowAutoLayout = sheet.layoutTemplate !== 'manual';
352→  const autoEntries = allowAutoLayout
353→    ? sourceEntries.filter((entry) => !entry.viewport.lockAutoLayout)
354→    : [];
355→  const manualEntries = sourceEntries.filter((entry) => entry.viewport.lockAutoLayout);
356→  const autoRects = layoutAutoViewports(autoEntries, zones.contentArea);
357→
358→  const sceneViewports = sourceEntries.map((entry) => {
359→    const rect = autoRects.get(entry.viewport.id)
360→      || fitViewportToSheet(entry.viewport, sheet);
361→    return buildViewportScene(entry.viewport, entry.source, sheet, rect);
362→  });
363→
364→  const sheetIndex = (project?.sheets || []).findIndex((entry) => entry.id === sheet.id);
365→
366→  return {
367→    paper,
368→    title: getSheetDisplayLabel(sheet, Math.max(0, sheetIndex)),
369→    border: zones.border,
370→    liveArea: zones.liveArea,
371→    contentArea: zones.contentArea,
372→    footer: zones.footer,
373→    titleBlock: buildTitleBlock(project, sheet, zones.titleBlock, Math.max(0, sheetIndex), sceneViewports),
374→    viewports: sceneViewports,
375→    graphics: {
376→      colors: SHEET_COLORS,
377→      drawing: DRAWING_GRAPHICS,
378→    },
379→    manualViewportCount: manualEntries.length,
380→  };
381→}
382→
383→export function materializeSheetViewportFrames(project, sheet) {
384→  if (!sheet) return sheet;
385→
386→  const scene = buildSheetScene(project, {
387→    ...sheet,
388→    layoutTemplate: 'auto',
389→  });
390→
391→  if (!scene) return sheet;
392→
393→  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
394→
395→  return {
396→    ...sheet,
397→    layoutTemplate: 'manual',
398→    viewports: (sheet.viewports || []).map((viewport) => {
399→      const frame = frameById.get(viewport.id);
400→      if (!frame) {
401→        return {
402→          ...viewport,
403→          lockAutoLayout: true,
404→        };
405→      }
406→
407→      return {
408→        ...viewport,
409→        x: frame.x,
410→        y: frame.y,
411→        width: frame.width,
412→        height: frame.height,
413→        rotation: frame.rotation || 0,
414→        lockAutoLayout: true,
415→      };
416→    }),
417→  };
418→}
419→
420→export function fitViewportToSheet(viewport, sheet) {
421→  const paper = getPaperPreset(sheet.paperSize);
422→  const zones = buildSheetZones(paper);
423→  const captionClearance = getCaptionClearance(viewport);
424→  const captionAbove = viewport.captionPosition === 'above' ? captionClearance : 0;
425→  const captionBelow = viewport.captionPosition === 'below' ? captionClearance : 0;
426→  const width = clamp(
427→    viewport.width,
428→    SHEET_TOKENS.viewportMinWidth,
429→    zones.contentArea.width
430→  );
431→  const height = clamp(
432→    viewport.height,
433→    SHEET_TOKENS.viewportMinHeight,
434→    zones.contentArea.height - captionClearance
435→  );
436→  const maxX = zones.contentArea.x + zones.contentArea.width - width;
437→  const minY = zones.contentArea.y + captionAbove;
438→  const maxY = zones.contentArea.y + zones.contentArea.height - height - captionBelow;
439→
440→  return {
441→    ...viewport,
442→    ...snapRectToGrid({
443→      x: clamp(viewport.x, zones.contentArea.x, maxX),
444→      y: clamp(viewport.y, minY, Math.max(minY, maxY)),
445→      width,
446→      height,
447→    }),
448→  };
449→}
450→
451→export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
452→  const paper = getPaperPreset(sheet.paperSize);
453→  const zones = buildSheetZones(paper);
454→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
455→  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
456→  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
457→  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
458→  const baseScale = source.kind === '3d_preview' ? 1 : Math.max(1, scale);
459→  const width = clamp(
460→    source.kind === '3d_preview'
461→      ? zones.contentArea.width * 0.72
462→      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
463→    role === 'primary' ? 120 : 84,
464→    role === 'primary' ? zones.contentArea.width * 0.72 : zones.contentArea.width * 0.44
465→  );
466→  const height = clamp(
467→    source.kind === '3d_preview'
468→      ? zones.contentArea.height * 0.54
469→      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
470→    role === 'primary' ? 96 : 72,
471→    role === 'primary' ? zones.contentArea.height * 0.78 : zones.contentArea.height * 0.42
472→  );
473→
474→  return snapRectToGrid({
475→    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
476→    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
477→    width,
478→    height,
479→  });
480→}
