641→      });
642→
643→    case 'MARK_SAVED':
644→      return {
645→        ...state,
646→        isDirty: false,
647→        lastSavedAt: new Date().toISOString(),
648→        savedSnapshot: snapshotProject(state.project),
649→      };
650→
651→    case 'UNDO': {
652→      if (state.history.length === 0) return state;
653→      const previousProject = state.history[state.history.length - 1];
654→      return {
655→        ...state,
656→        project: previousProject,
657→        history: state.history.slice(0, -1),
658→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
659→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
660→      };
661→    }
662→
663→    case 'REDO': {
664→      if (state.future.length === 0) return state;
665→      const nextProject = state.future[0];
666→      return {
667→        ...state,
668→        project: nextProject,
669→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
670→        future: state.future.slice(1),
671→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
672→      };
673→    }
674→
675→    default:
676→      return state;
677→  }
678→}
679→
680→const initialProject = createProject();
681→
682→const initialState = {
683→  project: initialProject,
684→  isDirty: false,
685→  lastSavedAt: null,
686→  savedSnapshot: snapshotProject(initialProject),
687→  history: [],
688→  future: [],
689→};
690→
691→export function ProjectProvider({ children }) {
692→  const [state, dispatch] = useReducer(projectReducer, initialState);
693→  return (
694→    <ProjectContext.Provider value={{ state, dispatch }}>
695→      {children}
696→    </ProjectContext.Provider>
697→  );
698→}
699→
700→export function useProject() {
701→  const ctx = useContext(ProjectContext);
702→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
703→  const { state, dispatch } = ctx;
704→
705→  const duplicateFloor = (floorId) => {
706→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
707→    return floor ? createDuplicatedFloor(floor) : null;
708→  };
709→
710→  return {
711→    project: state.project,
712→    isDirty: state.isDirty,
713→    lastSavedAt: state.lastSavedAt,
714→    canUndo: state.history.length > 0,
715→    canRedo: state.future.length > 0,
716→    dispatch,
717→    duplicateFloor,
718→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
719→  };
720→}
