 29→    checkedBy: project.documentDefaults?.checkedBy ?? '',
 30→  };
 31→
 32→  if (project.floors.length === 0) {
 33→    project.floors = [createFloor('Ground Floor', 0)];
 34→  }
 35→
 36→  for (const floor of project.floors) {
 37→    if (!floor.id || !Array.isArray(floor.walls)) {
 38→      throw new Error('Invalid floor structure');
 39→    }
 40→  }
 41→
 42→  // Backfill missing room fields for old saves
