 47→    }
 48→    if (floor.floorToFloorHeight === undefined) {
 49→      floor.floorToFloorHeight = WALL_HEIGHT;
 50→    }
 51→    if (floor.elevation === undefined) {
 52→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 53→    }
 54→    delete floor.level;
 55→
 56→    if (!floor.rooms) floor.rooms = [];
 57→    for (const room of floor.rooms) {
 58→      if (!room.points) room.points = [];
 59→      if (room.area === undefined) room.area = 0;
 60→    }
 61→  });
 62→
 63→  // Backfill door/window type fields for old saves
 64→  for (const floor of project.floors) {
 65→    if (!floor.doors) floor.doors = [];
 66→    for (const door of floor.doors) {
 67→      if (!door.type) door.type = 'swing';
 68→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 69→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 70→    }
 71→    if (!floor.windows) floor.windows = [];
 72→    for (const win of floor.windows) {
