 80→    if (!floor.beams) floor.beams = [];
 81→    if (!floor.stairs) floor.stairs = [];
 82→    if (!floor.landings) floor.landings = [];
 83→    if (!floor.annotations) floor.annotations = [];
 84→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 85→    // Migrate single slab → slabs array
 86→    if (floor.slab !== undefined) {
