35→export function reorderPhases(phases, movedId, newOrder) {
36→  const sorted = sortPhases(phases);
37→  const moved = sorted.find(p => p.id === movedId);
38→  if (!moved) return sorted;
39→
40→  const others = sorted.filter(p => p.id !== movedId);
41→  const clamped = Math.max(0, Math.min(newOrder, others.length));
42→  others.splice(clamped, 0, moved);
43→
44→  return others.map((p, i) => ({ ...p, order: i }));
45→}
