 71→export default function Sidebar() {
 72→  const { project, dispatch, duplicateFloor } = useProject();
 73→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
 74→  const orderedFloors = getOrderedFloors(project);
 75→  const orderedPhases = getOrderedPhases(project);
 76→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 77→  const [collapsedSections, setCollapsedSections] = useState({
 78→    floors: false,
 79→    sheets: false,
 80→    phases: false,
 81→    slabs: false,
 82→    walls: false,
 83→    annotations: false,
 84→    beams: false,
 85→    stairs: false,
 86→    landings: false,
 87→    doors: false,
 88→    windows: false,
 89→    columns: false,
 90→    rooms: false,
 91→  });
 92→
 93→  const selectObject = (id, type) => {
 94→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 95→  };
 96→
 97→  const selectFloor = (floorId) => {
 98→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 99→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
100→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
101→  };
102→
103→  const setActiveFloor = (floorId) => {
104→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
105→  };
106→
107→  const addFloor = () => {
108→    const nextFloor = createFloorAboveHighest(project.floors || []);
109→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
110→    selectFloor(nextFloor.id);
111→  };
112→
113→  const handleDuplicateFloor = (floorToDuplicate) => {
114→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
115→    if (!duplicatedFloor) return;
116→
117→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
118→    selectFloor(duplicatedFloor.id);
119→  };
120→
121→  const handleDeleteFloor = (floorToDelete) => {
122→    if ((project.floors || []).length <= 1) return;
123→
124→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
125→    if (!confirmed) return;
126→
127→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
128→    const fallbackFloor = remainingFloors[0] || null;
129→
130→    dispatch({
131→      type: 'FLOOR_DELETE',
132→      floorId: floorToDelete.id,
133→      fallbackFloorId: fallbackFloor?.id ?? null,
134→    });
135→
136→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
137→      if (workspaceMode === 'model') {
138→        selectFloor(fallbackFloor.id);
139→      } else {
140→        setActiveFloor(fallbackFloor.id);
141→      }
142→    }
143→  };
144→
145→  const addPhase = () => {
146→    const nextOrder = getNextPhaseOrder(project.phases || []);
147→    const color = PHASE_COLORS[nextOrder % PHASE_COLORS.length];
148→    const phase = createPhase(`Phase ${nextOrder + 1}`, nextOrder, color);
149→    dispatch({ type: 'PHASE_ADD', phase });
150→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: phase.id });
151→    editorDispatch({ type: 'SELECT_OBJECT', id: phase.id, objectType: 'phase' });
152→  };
153→
154→  const selectPhase = (phaseId) => {
155→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId });
156→    if (phaseViewMode === 'all') {
157→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'single' });
158→    }
159→    editorDispatch({ type: 'SELECT_OBJECT', id: phaseId, objectType: 'phase' });
160→  };
161→
162→  const handleDeletePhase = (phase) => {
163→    if (!window.confirm(`Delete phase "${phase.name}"?`)) return;
164→    dispatch({ type: 'PHASE_DELETE', phaseId: phase.id });
165→    if (activePhaseId === phase.id) {
166→      editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
167→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
168→    }
169→    editorDispatch({ type: 'DESELECT' });
170→  };
171→
172→  const handleMovePhase = (phase, direction) => {
173→    const newOrder = phase.order + direction;
174→    const reordered = reorderPhases(project.phases || [], phase.id, newOrder);
175→    dispatch({ type: 'PHASE_REORDER', phases: reordered });
176→  };
177→
178→  const addSheet = () => {
179→    const nextIndex = (project.sheets || []).length + 1;
180→    const sheet = createSheet(`Sheet ${nextIndex}`, {
181→      drawingName: `Drawing ${nextIndex}`,
182→      number: `A${String(nextIndex).padStart(2, '0')}`,
183→    });
184→    dispatch({ type: 'SHEET_ADD', sheet });
185→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
186→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
187→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
188→  };
