  5→const EditorContext = createContext(null);
  6→
  7→function normalizeViewMode(viewMode) {
  8→  if (viewMode === 'elevation_side') return 'elevation_left';
  9→  return viewMode;
 10→}
 11→
 12→function getInitialModelViewport() {
 13→  return { panX: 400, panY: 300, zoom: DEFAULT_ZOOM };
 14→}
 15→
 16→function getInitialSheetViewport() {
 17→  return { panX: 120, panY: 80, zoom: 2 };
 18→}
