  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { sortPhases } from '@/domain/phaseModels';
  5→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  6→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  7→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  8→
  9→const ProjectContext = createContext(null);
 10→const HISTORY_LIMIT = 100;
 11→
 12→function snapshotProject(project) {
 13→  return JSON.stringify(project);
 14→}
 15→
 16→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 17→  const nextSnapshot = snapshotProject(nextProject);
 18→  const history = recordHistory
 19→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 20→    : state.history;
 21→
 22→  return {
 23→    ...state,
 24→    history,
 25→    future: recordHistory ? [] : state.future,
 26→    project: nextProject,
 27→    isDirty: nextSnapshot !== state.savedSnapshot,
 28→  };
 29→}
 30→
 31→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 32→  const nextFloors = state.project.floors.map((floor) => (
 33→    floor.id === floorId ? updater(floor) : floor
 34→  ));
 35→
 36→  return applyProjectUpdate(state, {
 37→    ...state.project,
 38→    updatedAt: new Date().toISOString(),
 39→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 40→  }, recordHistory);
 41→}
 42→
 43→function replaceFloors(state, floors, recordHistory = true) {
 44→  return applyProjectUpdate(state, {
 45→    ...state.project,
 46→    updatedAt: new Date().toISOString(),
 47→    floors: sortFloors(floors),
 48→  }, recordHistory);
 49→}
 50→
 51→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 52→  return {
 53→    ...project,
 54→    floors: project.floors.map((floor) => ({
 55→      ...floor,
 56→      stairs: (floor.stairs || []).map((stair) => ({
 57→        ...stair,
 58→        floorRelation: {
 59→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 60→            ? fallbackFloorId
 61→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 62→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 63→            ? fallbackFloorId
 64→            : (stair.floorRelation?.toFloorId ?? floor.id),
 65→        },
 66→      })),
 67→    })),
 68→    sheets: (project.sheets || []).map((sheet) => ({
 69→      ...sheet,
 70→      viewports: (sheet.viewports || []).map((viewport) => ({
 71→        ...viewport,
 72→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 73→          ? fallbackFloorId
 74→          : viewport.sourceFloorId,
 75→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 76→          ? null
 77→          : viewport.sourceRefId,
 78→      })),
 79→    })),
 80→  };
 81→}
 82→
 83→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 84→  const nextWall = { ...existingWall, ...wallUpdate };
 85→
 86→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 87→    nextWall.startAttachment = null;
 88→  }
 89→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 90→    nextWall.endAttachment = null;
 91→  }
 92→
 93→  return syncWallAttachmentPoints(nextWall, columns);
 94→}
 95→
 96→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 97→  return openings.map((opening) => {
 98→    if (opening.wallId !== wallId) return opening;
 99→
100→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
101→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
102→  });
103→}
104→
105→function projectReducer(state, action) {
106→  switch (action.type) {
107→    case 'PROJECT_NEW': {
108→      const newProject = {
109→        ...action.project,
110→        floors: sortFloors(action.project.floors || []),
111→      };
112→      return {
113→        project: newProject,
114→        isDirty: false,
115→        lastSavedAt: null,
116→        savedSnapshot: snapshotProject(newProject),
117→        history: [],
118→        future: [],
119→      };
120→    }
121→
122→    case 'PROJECT_LOAD': {
123→      const loadedProject = {
124→        ...action.project,
125→        floors: sortFloors(action.project.floors || []),
126→      };
127→      return {
128→        project: loadedProject,
129→        isDirty: false,
130→        lastSavedAt: action.savedAt || null,
131→        savedSnapshot: snapshotProject(loadedProject),
132→        history: [],
133→        future: [],
134→      };
135→    }
136→
137→    case 'PROJECT_SET_NAME':
138→      return applyProjectUpdate(state, {
139→        ...state.project,
140→        name: action.name,
141→        updatedAt: new Date().toISOString(),
142→      });
143→
144→    case 'PROJECT_UPDATE':
145→      return applyProjectUpdate(state, {
146→        ...state.project,
147→        ...action.updates,
148→        updatedAt: new Date().toISOString(),
149→      });
150→
151→    case 'FLOOR_ADD':
152→      return replaceFloors(state, [...state.project.floors, action.floor]);
153→
154→    case 'FLOOR_UPDATE':
155→      return updateFloor(state, action.floor.id, (floor) => {
156→        const mergedFloor = {
157→          ...floor,
158→          ...action.floor,
159→        };
160→        const nextElevation = getFloorElevation(mergedFloor);
161→        const deltaElevation = nextElevation - getFloorElevation(floor);
162→        return {
163→          ...shiftFloorAbsoluteElements({
164→            ...mergedFloor,
165→            elevation: getFloorElevation(floor),
166→          }, deltaElevation),
167→          elevation: nextElevation,
168→        };
169→      }, true, { sort: true });
170→
171→    case 'FLOOR_DUPLICATE': {
172→      const duplicatedFloor = action.floor;
173→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
174→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
175→
176→      const shiftedFloors = state.project.floors.map((floor) => {
177→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
178→
179→        const previousLevelIndex = getFloorLevelIndex(floor);
180→        return shiftFloorElevationData({
181→          ...floor,
182→          name: floor.name === getDefaultFloorName(previousLevelIndex)
183→            ? getDefaultFloorName(previousLevelIndex + 1)
184→            : floor.name,
185→          levelIndex: previousLevelIndex + 1,
186→        }, elevationShift);
187→      });
188→
189→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
190→    }
191→
192→    case 'FLOOR_DELETE': {
193→      if (state.project.floors.length <= 1) return state;
194→
195→      const nextProject = replaceDeletedFloorReferences(
196→        {
197→          ...state.project,
198→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
199→        },
200→        action.floorId,
201→        action.fallbackFloorId
202→      );
203→
204→      return applyProjectUpdate(state, {
205→        ...nextProject,
206→        updatedAt: new Date().toISOString(),
207→        floors: sortFloors(nextProject.floors),
208→      });
209→    }
210→
211→    case 'SHEET_ADD':
212→      return applyProjectUpdate(state, {
213→        ...state.project,
214→        updatedAt: new Date().toISOString(),
215→        sheets: [...(state.project.sheets || []), action.sheet],
216→      });
217→
218→    case 'SHEET_UPDATE':
219→      return applyProjectUpdate(state, {
220→        ...state.project,
221→        updatedAt: new Date().toISOString(),
222→        sheets: (state.project.sheets || []).map((sheet) => (
223→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
224→        )),
225→      });
226→
227→    case 'SHEET_DELETE':
228→      return applyProjectUpdate(state, {
229→        ...state.project,
230→        updatedAt: new Date().toISOString(),
231→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
232→      });
233→
234→    case 'SHEET_VIEWPORT_ADD':
235→      return applyProjectUpdate(state, {
236→        ...state.project,
237→        updatedAt: new Date().toISOString(),
238→        sheets: (state.project.sheets || []).map((sheet) => (
239→          sheet.id === action.sheetId
240→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
241→            : sheet
242→        )),
243→      });
244→
245→    case 'SHEET_VIEWPORT_UPDATE':
246→      return applyProjectUpdate(state, {
247→        ...state.project,
248→        updatedAt: new Date().toISOString(),
249→        sheets: (state.project.sheets || []).map((sheet) => (
250→          sheet.id === action.sheetId
251→            ? {
252→                ...sheet,
253→                viewports: (sheet.viewports || []).map((viewport) => (
254→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
255→                )),
256→              }
257→            : sheet
258→        )),
259→      });
260→
261→    case 'SHEET_VIEWPORT_DELETE':
262→      return applyProjectUpdate(state, {
263→        ...state.project,
264→        updatedAt: new Date().toISOString(),
265→        sheets: (state.project.sheets || []).map((sheet) => (
266→          sheet.id === action.sheetId
267→            ? {
268→                ...sheet,
269→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
270→              }
271→            : sheet
272→        )),
273→      });
274→
275→    case 'WALL_ADD':
276→      return updateFloor(state, action.floorId, f => ({
277→        ...f,
278→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
279→      }));
280→
281→    case 'WALL_UPDATE':
282→      return updateFloor(state, action.floorId, f => {
283→        let updatedWall = null;
284→        const walls = f.walls.map((wall) => {
285→          if (wall.id !== action.wall.id) return wall;
286→
287→          updatedWall = mergeWallUpdate(wall, action.wall, f.columns || []);
288→          return updatedWall;
289→        });
290→
291→        if (!updatedWall) {
292→          return f;
293→        }
294→
295→        const nextWallLength = wallLength(updatedWall);
296→
297→        return {
298→          ...f,
299→          walls,
300→          doors: clampWallMountedOpenings(f.doors, updatedWall.id, nextWallLength),
301→          windows: clampWallMountedOpenings(f.windows, updatedWall.id, nextWallLength),
302→        };
303→      });
304→
305→    case 'WALL_DELETE': {
306→      const wallId = action.wallId;
307→      return updateFloor(state, action.floorId, f => ({
308→        ...f,
309→        walls: f.walls.filter(w => w.id !== wallId),
310→        doors: f.doors.filter(d => d.wallId !== wallId),
311→        windows: f.windows.filter(w => w.wallId !== wallId),
312→      }));
313→    }
314→
315→    case 'DOOR_ADD':
316→      return updateFloor(state, action.floorId, f => ({
317→        ...f,
318→        doors: [...f.doors, action.door],
319→      }));
320→
321→    case 'DOOR_UPDATE':
