572→      }));
573→    case 'COLUMN_UPDATE':
574→      return updateFloor(state, action.floorId, f => {
575→        const nextColumns = (f.columns || []).map(c => (
576→          c.id === action.column.id ? { ...c, ...action.column } : c
577→        ));
578→        return {
579→          ...f,
