699→export function ProjectProvider({ children }) {
700→  const [state, dispatch] = useReducer(projectReducer, initialState);
701→  return (
702→    <ProjectContext.Provider value={{ state, dispatch }}>
703→      {children}
704→    </ProjectContext.Provider>
