708→export function useProject() {
709→  const ctx = useContext(ProjectContext);
710→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
711→  const { state, dispatch } = ctx;
712→
713→  const duplicateFloor = (floorId) => {
714→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
715→    return floor ? createDuplicatedFloor(floor) : null;
716→  };
717→
718→  return {
719→    project: state.project,
720→    isDirty: state.isDirty,
721→    lastSavedAt: state.lastSavedAt,
722→    canUndo: state.history.length > 0,
723→    canRedo: state.future.length > 0,
724→    dispatch,
725→    duplicateFloor,
726→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
727→  };
728→}
