      ...sheet,
      viewports: (sheet.viewports || []).map(vp => ({
        ...vp,
        phaseId: null,
        phaseViewMode: 'all',
      })),
    })),
  });
}
```

The Sidebar will need to:
1. Import `PHASE_TEMPLATES`, `applyPhaseTemplate` from `@/domain/phaseModels`.
2. Add local state: `const [showTemplateDropdown, setShowTemplateDropdown] = useState(false);`
3. Render a button + dropdown within the Phases section.
4. On template selection, call `dispatch({ type: 'PHASE_APPLY_TEMPLATE', phases: applyPhaseTemplate(selectedTemplate) })` and reset the editor's active phase.

### 5. Per-Phase Visibility Toggle

This is the most architecturally significant change because it affects the filter pipeline.

**Design decision:** The `visible` flag acts as an independent, per-phase override. If `phase.visible === false`, objects assigned to that phase are hidden regardless of `phaseViewMode`. This makes it an additional layer on top of the existing ALL/SINGLE/CUMULATIVE modes.

**Modifications to `src/domain/phaseFilter.js`:**

Update `isObjectVisibleInPhase` to check the phase's `visible` flag first:

```js
export function isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode) {
  // Check per-phase visibility override first
  if (obj.phaseId) {
    const objPhase = phases.find(p => p.id === obj.phaseId);
    if (objPhase && objPhase.visible === false) return false;
  }

  if (phaseViewMode === PHASE_VIEW.ALL) return true;
  if (!obj.phaseId) return true;
  if (!activePhaseId) return true;

  // ... rest unchanged
}
```

Also update `filterFloorByPhase` to respect visibility even when `phaseViewMode === 'all'`:

```js
export function filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode) {
  if (!floor) return floor;

  // Check if any phase has visible=false; if so, we need to filter even in ALL mode
  const hasHiddenPhases = phases.some(p => p.visible === false);
  if (phaseViewMode === PHASE_VIEW.ALL && !hasHiddenPhases && !activePhaseId) return floor;

  const isVisible = (obj) => isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode);
  // ... rest unchanged
}
```

Similarly update `filterProjectByPhase`:
```js
export function filterProjectByPhase(project, activePhaseId, phaseViewMode) {
  if (!project) return project;

  const phases = project.phases || [];
  const hasHiddenPhases = phases.some(p => p.visible === false);
  if (phaseViewMode === PHASE_VIEW.ALL && !hasHiddenPhases && !activePhaseId) return project;

  return {
    ...project,
    floors: project.floors.map(floor => filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode)),
  };
}
```

**Modifications to `src/ui/Sidebar.jsx` -- visibility toggle UI:**

Add an eye icon button to each phase item, between the color dot/name and the reorder buttons. This mirrors common layer-panel UX patterns from design tools.

Within the `.phaseItem` row, add:

```jsx
<button
  type="button"
  className={styles.phaseVisibilityBtn}
  onClick={(e) => {
    e.stopPropagation();
    dispatch({ type: 'PHASE_UPDATE', phase: { id: phase.id, visible: !phase.visible } });
  }}
  title={phase.visible ? 'Hide phase' : 'Show phase'}
>
  {phase.visible !== false ? <EyeOpenIcon /> : <EyeClosedIcon />}
</button>
```

New SVG icon components:

```jsx
function EyeOpenIcon() {
  return (
    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
      <path d="M1 7s2.5-4 6-4 6 4 6 4-2.5 4-6 4-6-4-6-4z" fill="none" stroke="currentColor" strokeWidth="1.2" />
      <circle cx="7" cy="7" r="1.5" fill="currentColor" />
    </svg>
  );
}

function EyeClosedIcon() {
  return (
    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
      <path d="M1 7s2.5-4 6-4 6 4 6 4-2.5 4-6 4-6-4-6-4z" fill="none" stroke="currentColor" strokeWidth="1.2" opacity="0.3" />
      <path d="M2 12l10-10" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" />
