  color: var(--color-text-primary);
}

.closeIcon {
  width: 16px;
  height: 16px;
}

.body {
  padding: var(--space-xl);
}

.modalBtn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 14px;
  border: 1px solid var(--color-border);
